#include<iostream>#include<vector>#include<queue>#include<climits>#define ll long longusing namespace std;void solve(){    ll n,k;    cin>>n>>k;    vector<ll>c(n);    for(int i=0;i<n;i++){        cin>>c[i];    }    vector<ll>colors[k+1];    for(int i=1;i<=k;i++){        colors[i].push_back(0);    }    for(int i=0;i<n;i++){        colors[c[i]].push_back(i + 1);    }    for(int i=1;i<=k;i++){        colors[i].push_back(n+1);    }     priority_queue<ll>jumps[k+1];     ll ans= INT_MAX;     for(int i=1;i<=k;i++){        for(int j=0;j<colors[i].size()-1;j++){            jumps[i].push(colors[i][j+1] - colors[i][j] - 1);        }        ll maxi= jumps[i].top();        jumps[i].pop();        if(maxi%2==0){            jumps[i].push(maxi/2);            jumps[i].push((maxi/2) - 1);        }        else{            jumps[i].push(maxi/2);            jumps[i].push(maxi/2);        }        ans= min(ans,jumps[i].top());    }     cout<<ans<<"\n";}int main(){    ios_base::sync_with_stdio(false);    cin.tie(NULL);    int t;    cin>>t;    while(t--){        solve();    }}